// ---------------------------------------------------------------------------
// Deterministic scorer — runs server-side. Doesn't require LLM.
// The LLM is used for response generation (below) and for edge cases where
// the deterministic model is uncertain.
// ---------------------------------------------------------------------------

function scoreLead(p) {
  const notesDemo = [];
  const notesBeh = [];
  const notesCo = [];
  const notesCom = [];

  // Demographic fit (0–20 raw, then scaled by 1.0 into the 20-pt bucket)
  let icpMatch = 0;
  const titleMatch = !!p.person?.title && p.icp.idealTitles.some((t) =>
    p.person.title.toLowerCase().includes(t.toLowerCase()),
  );
  const sizeMatch =
    !!p.company?.employeeCount &&
    (!p.icp.idealCompanySizeMin || p.company.employeeCount >= p.icp.idealCompanySizeMin) &&
    (!p.icp.idealCompanySizeMax || p.company.employeeCount <= p.icp.idealCompanySizeMax);
  const industryMatch =
    !!p.company?.industryNaics &&
    p.icp.idealIndustries.some((i) =>
      p.company.industryNaics.toLowerCase().includes(i.toLowerCase()),
    );
  const fitCount = [titleMatch, sizeMatch, industryMatch].filter(Boolean).length;
  if (fitCount === 3) {
    icpMatch = 20;
    notesDemo.push('Exact ICP match (title + size + industry)');
  } else if (fitCount === 2) {
    icpMatch = 15;
    notesDemo.push('Strong fit (2 of 3 ICP dimensions)');
  } else if (fitCount === 1) {
    icpMatch = 8;
    notesDemo.push('Partial fit (1 of 3 ICP dimensions)');
  } else {
    notesDemo.push('No clear ICP fit');
  }

  let roleAuthority = 0;
  switch (p.person?.seniority) {
    case 'c_suite':
      roleAuthority = 5;
      notesDemo.push('Final decision maker (C-suite/owner)');
      break;
    case 'vp':
    case 'director':
      roleAuthority = 3;
      notesDemo.push('Key influencer (VP/Director)');
      break;
    case 'manager':
    case 'senior_ic':
      roleAuthority = 2;
      notesDemo.push('Evaluator (manager/senior IC)');
      break;
    case 'gatekeeper':
      roleAuthority = -3;
      notesDemo.push('Gatekeeper — likely research, not buying');
      break;
    default:
      roleAuthority = 0;
  }

  const demographicFitRaw = icpMatch + roleAuthority; // up to ~25, clamp
  const demographicFit = Math.max(0, Math.min(20, demographicFitRaw));

  // Behavioral intent (0–35)
  let buyingStageSignals = 0;
  if (p.behavior.pricingPageVisits >= 1) {
    buyingStageSignals += p.behavior.pricingPageVisits >= 3 ? 15 : 10;
    notesBeh.push(
      `Pricing page visited ${p.behavior.pricingPageVisits}× (${p.behavior.pricingPageTimeSeconds}s)`,
    );
  }
  if (p.behavior.demoPageVisited) {
    buyingStageSignals += 10;
    notesBeh.push('Demo page visited');
  }
  if (p.behavior.comparisonPageVisited) {
    buyingStageSignals += 12;
    notesBeh.push('Comparison page visited');
  }
  if (p.behavior.integrationPageVisited) {
    buyingStageSignals += 8;
    notesBeh.push('Integration page visited');
  }
  if (p.behavior.caseStudiesDownloaded > 0) {
    buyingStageSignals += 7;
    notesBeh.push(`${p.behavior.caseStudiesDownloaded} case study downloads`);
  }
  if (p.behavior.contactSalesFormSubmitted) {
    buyingStageSignals += 20;
    notesBeh.push('Contact sales form submitted');
  }
  if (p.behavior.emailReplies > 0) {
    buyingStageSignals += 15;
    notesBeh.push('Replied to email — high intent signal');
  }
  if (p.behavior.webinarAttended) {
    buyingStageSignals += 10;
    notesBeh.push('Attended webinar');
  }
  if (p.behavior.sessionDepthMax >= 5) {
    buyingStageSignals += 8;
    notesBeh.push(`Deep session (${p.behavior.sessionDepthMax} pages)`);
  }
  if (p.behavior.calendarLinkClicked) {
    buyingStageSignals += 20;
    notesBeh.push('Clicked calendar link');
  }

  let engagementVelocity = 0;
  if (p.behavior.activityLast24h) {
    engagementVelocity += 10;
    notesBeh.push('Active in last 24h');
  } else if (p.behavior.activityLast7d) {
    engagementVelocity += 5;
    notesBeh.push('Active in last 7d');
  } else if (p.behavior.dormantDays >= 30) {
    engagementVelocity -= 5;
    notesBeh.push(`Dormant ${p.behavior.dormantDays} days`);
  }

  const behRaw = buyingStageSignals + engagementVelocity;
  const behavioralIntent = Math.max(0, Math.min(35, behRaw));

  // Company fit (0–25)
  let coPositive = 0;
  let coNegative = 0;
  if (sizeMatch) {
    coPositive += 15;
    notesCo.push('Company size in ICP range');
  }
  if (industryMatch) {
    coPositive += 10;
    notesCo.push('Industry in ICP');
  }
  const recentFunding =
    p.company?.fundingHistory?.some(
      (f) => Date.now() - new Date(f.closedAt).getTime() < 365 * 24 * 60 * 60 * 1000,
    ) ?? false;
  if (recentFunding) {
    coPositive += 8;
    notesCo.push('Recently funded (last 12mo) — expansion budget');
  }
  if ((p.company?.employeeGrowthYoy ?? 0) > 0.3) {
    coPositive += 7;
    notesCo.push('Employee growth >30% YoY');
  }

  const domain = p.email.split('@')[1]?.toLowerCase() ?? '';
  if (p.icp.deadbeatList.some((d) => domain.includes(d.toLowerCase()))) {
    coNegative -= 20;
    notesCo.push('Domain in deadbeat list');
  }
  if (p.icp.idealCompanySizeMin && (p.company?.employeeCount ?? 0) < p.icp.idealCompanySizeMin) {
    coNegative -= 10;
    notesCo.push('Size below ICP floor');
  }
  const geoServed =
    !p.icp.servedGeographies.length ||
    p.icp.servedGeographies.some(
      (g) =>
        p.company?.hq?.country?.toLowerCase().includes(g.toLowerCase()) ||
        p.person?.location?.country?.toLowerCase().includes(g.toLowerCase()),
    );
  if (!geoServed) {
    coNegative -= 10;
    notesCo.push('Geography not served');
  }

  const coRaw = coPositive + coNegative;
  const companyFit = Math.max(0, Math.min(25, coRaw));

  // Commitment signals (0–20)
  let messageQuality = 0;
  if (p.intake?.specificProductQuestion) {
    messageQuality += 10;
    notesCom.push('Specific product question');
  }
  if (p.intake?.useCaseDescribed) {
    messageQuality += 8;
    notesCom.push('Clear use case described');
  }
  if (p.intake?.timelineMentioned) {
    messageQuality += 12;
    notesCom.push('Timeline mentioned');
  }
  if (p.intake?.budgetMentioned) {
    messageQuality += 15;
    notesCom.push('Budget mentioned');
  }
  if (p.intake?.competitiveEvaluationMentioned) {
    messageQuality += 10;
    notesCom.push('Competitive evaluation mentioned');
  }
  if (p.intake?.message && p.intake.message.length < 15 && !p.intake.specificProductQuestion) {
    messageQuality -= 5;
    notesCom.push('Vague "info please" message');
  }

  let verification = 0;
  if (!p.personalEmail && !p.roleEmail) {
    verification += 8;
    notesCom.push('Business email');
  }
  if (p.person?.linkedinUrl) {
    verification += 5;
    notesCom.push('LinkedIn profile verified');
  }
  if (p.behavior.calendarLinkClicked) {
    verification += 20;
  }

  const comRaw = messageQuality + verification;
  const commitmentSignals = Math.max(0, Math.min(20, comRaw));

  // Total
  const total = Math.round(
    demographicFit + behavioralIntent + companyFit + commitmentSignals,
  );

  // Tier
  let tier ;
  if (total >= 80) tier = 'hot';
  else if (total >= 60) tier = 'warm_high';
  else if (total >= 40) tier = 'warm';
  else if (total >= 20) tier = 'cool';
  else tier = 'junk';

  // Top signals extraction
  const topPredictiveSignals = [
    ...notesBeh.filter((n) => /pricing|comparison|contact sales|replied|calendar|demo/.test(n)),
    ...notesCo.filter((n) => /funded|growth/.test(n)),
    ...notesCom.filter((n) => /budget|timeline/.test(n)),
  ].slice(0, 5);

  const topRiskSignals = [
    ...notesCo.filter((n) => /deadbeat|below|not served/.test(n)),
    ...notesCom.filter((n) => /vague/.test(n)),
    ...notesDemo.filter((n) => /Gatekeeper/.test(n)),
  ];

  const recommendedAction = tierActionRecommendation(tier);

  return {
    leadId: p.leadId,
    total,
    tier,
    components: {
      demographicFit: {
        score: demographicFit,
        icpMatch,
        roleAuthority,
        notes: notesDemo,
      },
      behavioralIntent: {
        score: behavioralIntent,
        buyingStageSignals,
        engagementVelocity,
        notes: notesBeh,
      },
      companyFit: {
        score: companyFit,
        positive: coPositive,
        negative: coNegative,
        notes: notesCo,
      },
      commitmentSignals: {
        score: commitmentSignals,
        messageQuality,
        verification,
        notes: notesCom,
      },
    },
    topPredictiveSignals,
    topRiskSignals,
    recommendedAction,
    scoredAt: new Date().toISOString(),
  };
}

function tierActionRecommendation(tier) {
  switch (tier) {
    case 'hot':
      return 'Respond within 5 minutes (9x conversion lift — HBR). Draft personalized message with research. Auto-suggest meeting times.';
    case 'warm_high':
      return 'Same-day response (1h window). AI draft + nurture if no response within 24h.';
    case 'warm':
      return '24h response window. Enroll in automated nurture sequence (WF7). Email + retargeting audience.';
    case 'cool':
      return 'Long-term nurture. Monthly newsletter only. Trigger re-engagement on behavior change.';
    case 'junk':
      return 'Flag and file. Weekly review. Never delete — a mis-flag teaches the model.';
  }
}

