function buildLeadResponsePrompt(
  ctx,
  lead,
  score,
) {
  const addendum = `
WORKFLOW #2 — LEAD SCORING, RESPONSE GENERATION PHASE

You are the founder's SDR with 10 years at a top-performing B2B sales org.
A lead just came in and the scoring engine classified them as ${score.tier.toUpperCase()}
(${score.total}/100). Your job: draft a first-touch message that feels like
it was written by a smart human who actually read their profile.

HARD RULES
- 80–200 words. Any longer and they won't read; any shorter and it feels lazy.
- NEVER start with "Hi {{name}}, I see you're a [title]..." — that's dead on arrival.
- Open with GENUINE personalization from the enrichment payload: a specific
  detail only a real reader would notice (their company's recent funding,
  their tenure at the role, a behavior they took on our site).
- Reference a SPECIFIC behavior they took: "I saw you were looking at our
  pricing and comparison with [competitor] yesterday…"
- Offer IMMEDIATE value before asking for anything. One sentence of concrete
  help, not a platitude.
- Low-friction CTA: give them permission to ignore it. "If this is relevant,
  grab 15 min here: [CAL_LINK]. If not, just ignore and I won't bug you."
- Signature with quiet social proof: the founder's name + "previously helped
  [N]+ teams at [peer companies]".

QUALITY GATES (scored before send — must clear all)
- Personalization specificity: 0–100, must be >70. Reference at least 2
  unique facts from enrichment.
- Length: 80–200 words.
- CTA clarity: exactly one action, with a fallback.
- Tone match: matches brand voice (see BRAND CONTEXT above).
- No typos, no AI-ese ("I hope this email finds you well"), no superlatives
  without evidence.

PSYCHOLOGY LEVERS TO CONSIDER
- Reciprocity (Cialdini): open with a gift — a specific insight, a Loom
  link, a cheat-sheet. Before asking.
- Authority (Cialdini): quiet signals in the signature — not "I'm the best
  in the industry" but "previously helped 200+ teams at [peer brands]".
- Liking (Cialdini): genuine compliments are rare and powerful when tied
  to something specific they did publicly.
- Low-friction CTA (Kahneman): give the opt-out explicitly. It removes
  the defensive reading and raises response rate.
- StoryBrand: the prospect is the hero. You are the guide. Name the stakes
  (what they'll hit if unaddressed) and the transformation briefly.

OUTPUT FORMAT: strict JSON
{
  "subject": string,            // 30–60 chars, specific
  "body": string,               // 80–200 words, markdown
  "personalizationScore": number,  // self-assessed 0–100
  "qualityChecks": {
    "personalization": number,   // 0–100
    "length": boolean,           // 80–200 words?
    "ctaClarity": boolean,
    "toneMatch": boolean,
    "noTypos": boolean
  },
  "predictedResponseRate": { "low": number, "high": number },  // as decimals
  "psychologyLevers": string[],  // 1–3 you used, by name
  "frameworkJustification": string // 1–2 sentences naming WHY these levers
}
`.trim();

  const user = `
LEAD
  Tier: ${score.tier.toUpperCase()} (${score.total}/100)
  Top predictive signals: ${score.topPredictiveSignals.join(' | ') || '(none)'}
  Top risk signals: ${score.topRiskSignals.join(' | ') || '(none)'}

PERSON
  ${JSON.stringify(lead.person ?? {}, null, 2)}

COMPANY
  ${JSON.stringify(lead.company ?? {}, null, 2)}

BEHAVIOR
  ${JSON.stringify(lead.behavior, null, 2)}

INTAKE MESSAGE
  ${lead.intake?.message ?? '(none)'}

INTENT SIGNALS
  ${JSON.stringify(lead.intentSignals ?? {}, null, 2)}

SIGNATURE CONTEXT
  Founder name + role from BRAND CONTEXT.
`.trim();

  return {
    system: buildSystemPrompt(ctx, addendum),
    user,
  };
}

// ---------------------------------------------------------------------------
// Routing rules — territory + expertise + workload
// ---------------------------------------------------------------------------

function routeLead(
  lead,
  score,
  rules,
  currentLoads,
) {
  for (const rule of rules) {
    const decision = tryRule(lead, score, rule, currentLoads);
    if (decision) return decision;
  }
  return {
    leadId: lead.leadId,
    ownerId: null,
    rationale: 'No routing rule matched — falling back to shared queue',
    matchedRule: 'round_robin',
    slaMinutes: slaForTier(score.tier),
  };
}

function tryRule(
  lead,
  score,
  rule,
  currentLoads,
) {
  switch (rule.kind) {
    case 'account_based': {
      const domain = lead.email.split('@')[1]?.toLowerCase() ?? '';
      const owner = rule.accountOwnerMap[domain];
      if (owner) {
        return {
          leadId: lead.leadId,
          ownerId: owner,
          rationale: `Account-based: ${domain} mapped to ${owner}`,
          matchedRule: 'account_based',
          slaMinutes: slaForTier(score.tier),
        };
      }
      return null;
    }
    case 'territory': {
      const country = lead.company?.hq?.country ?? lead.person?.location?.country;
      const match = rule.rules.find(
        (r) => r.country && country && r.country.toLowerCase() === country.toLowerCase(),
      );
      if (match) {
        return {
          leadId: lead.leadId,
          ownerId: match.ownerId,
          rationale: `Territory: ${country} → ${match.ownerId}`,
          matchedRule: 'territory',
          slaMinutes: slaForTier(score.tier),
        };
      }
      return null;
    }
    case 'industry': {
      const ind = lead.company?.industryNaics?.toLowerCase();
      const match = rule.rules.find((r) => ind && ind.includes(r.industry.toLowerCase()));
      if (match) {
        return {
          leadId: lead.leadId,
          ownerId: match.ownerId,
          rationale: `Industry expertise: ${ind} → ${match.ownerId}`,
          matchedRule: 'industry',
          slaMinutes: slaForTier(score.tier),
        };
      }
      return null;
    }
    case 'deal_size': {
      const acv = estimateDealSize(lead);
      const ordered = [...rule.rules].sort((a, b) => b.minAcv - a.minAcv);
      const match = ordered.find((r) => acv >= r.minAcv);
      if (match) {
        return {
          leadId: lead.leadId,
          ownerId: match.ownerId,
          rationale: `Deal size $${acv.toLocaleString()} matched tier ≥$${match.minAcv.toLocaleString()}`,
          matchedRule: 'deal_size',
          slaMinutes: slaForTier(score.tier),
        };
      }
      return null;
    }
    case 'workload_balanced': {
      const eligible = rule.owners
        .map((o) => ({ owner: o, load: currentLoads[o] ?? 0 }))
        .filter((e) => e.load < rule.maxActiveLeads)
        .sort((a, b) => a.load - b.load);
      if (eligible.length) {
        return {
          leadId: lead.leadId,
          ownerId: eligible[0].owner,
          rationale: `Workload-balanced: ${eligible[0].owner} has ${eligible[0].load} active leads`,
          matchedRule: 'workload_balanced',
          slaMinutes: slaForTier(score.tier),
        };
      }
      return null;
    }
    case 'round_robin': {
      if (rule.owners.length === 0) return null;
      const sorted = rule.owners
        .map((o) => ({ owner: o, load: currentLoads[o] ?? 0 }))
        .sort((a, b) => a.load - b.load);
      return {
        leadId: lead.leadId,
        ownerId: sorted[0].owner,
        rationale: `Round robin to least-loaded owner (${sorted[0].load} active)`,
        matchedRule: 'round_robin',
        slaMinutes: slaForTier(score.tier),
      };
    }
  }
}

function slaForTier(tier) {
  switch (tier) {
    case 'hot':
      return 5;
    case 'warm_high':
      return 60;
    case 'warm':
      return 24 * 60;
    case 'cool':
      return 7 * 24 * 60;
    case 'junk':
      return 30 * 24 * 60;
  }
}

function estimateDealSize(lead) {
  const size = lead.company?.employeeCount ?? 0;
  if (size >= 1000) return 150_000; // enterprise
  if (size >= 200) return 40_000; // mid-market
  if (size >= 50) return 12_000; // SMB+
  if (size >= 10) return 4_000; // small
  return 1_000;
}

// ---------------------------------------------------------------------------
// Buying committee detection (B2B)
// ---------------------------------------------------------------------------

function detectBuyingCommittee(leads, scores) {
  const byDomain = new Map();
  for (const l of leads) {
    const domain = l.email.split('@')[1]?.toLowerCase() ?? '';
    if (!domain || l.roleEmail || l.personalEmail) continue;
    if (!byDomain.has(domain)) byDomain.set(domain, []);
    byDomain.get(domain).push(l);
  }
  const committees = [];
  for (const [domain, ls] of byDomain.entries()) {
    if (ls.length < 2) continue; // single contact ≠ committee
    const sorted = ls.sort((a, b) => a.createdAt.localeCompare(b.createdAt));
    const totalScore = ls.reduce(
      (sum, l) => sum + (scores.find((s) => s.leadId === l.leadId)?.total ?? 0),
      0,
    );
    committees.push({
      companyDomain: domain,
      members: sorted.map((l) => ({
        leadId: l.leadId,
        role: inferCommitteeRole(l),
        seniority: l.person?.seniority ?? 'unknown',
        name: `${l.person?.firstName ?? ''} ${l.person?.lastName ?? ''}`.trim(),
        title: l.person?.title ?? '',
      })),
      firstContactAt: sorted[0].createdAt,
      lastActivityAt: sorted[sorted.length - 1].createdAt,
      totalActivityScore: totalScore,
      isActiveDeal: totalScore > 100,
    });
  }
  return committees;
}

function inferCommitteeRole(l) {
  const title = (l.person?.title ?? '').toLowerCase();
  if (l.person?.seniority === 'c_suite') return 'economic_buyer';
  if (title.includes('engineer') || title.includes('architect') || title.includes('technical'))
    return 'technical_evaluator';
  if (title.includes('ops') || title.includes('admin') || title.includes('user'))
    return 'user';
  if (l.person?.seniority === 'vp' || l.person?.seniority === 'director') return 'champion';
  return 'influencer';
}

